const fs=require('fs');
const data=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(data[idx++]);
let out=[];
for(let t=0;t<T;++t){
  const N=Number(data[idx++]);
  let orAll=0;
  for(let i=0;i<N;++i){
    const x=Number(data[idx++]);
    orAll|=x;
  }
  let cnt=0;
  let v=orAll>>>0;
  while(v){cnt+=v&1;v>>>==1;}
  out.push(String(cnt));
}
console.log(out.join('\n'));
